import React from 'react'
import { graphql } from 'gatsby'
import Link from 'gatsby-link'
import get from 'lodash/get'
import Helmet from 'react-helmet'
import Layout from '../components/layout'

export const generatePostHeader = (title, path, date) => (
  <header className='post__header'>
    <h2 className='post__title'><Link to={path}>{title}</Link></h2>
    <time>{date}</time>
  </header>
)

export const generatePostFigure = (image, path) => image ? (
  <figure itemType='http://schema.org/ImageObject'>
    <Link to={path}>
      <img src={`${image}?w=800&&fit=crop&crop=focalpoint&auto=format`} itemProp='contentURL' alt='Post Figure' />
    </Link>
  </figure>
) : null

export const generatePosts = (posts) => posts.map(({
  node: {
    date,
    featured_image,
    meta,
    path,
    title,
  }
}, i) => {
  const header = generatePostHeader(title, path, date)
  const figure = generatePostFigure(featured_image, path)
  return (
  <article key={i} className='post--article'>
    {header}
    {figure}
    <p>{meta} <Link className='post__link--read-more' to={path}>[...]</Link></p>
    <hr />
  </article>
  )
})

const posts = get(this, 'props.data.allMarkdownRemark.edges')
export default () => (
  <Layout>
    <main className='main'>
      <Helmet title='Jeffry.in'>
        <meta name='twitter:description' property='og:description' content='Jeffry.in is the blog of Jeffry Wainwright, an engineer living in California.' />
        <link rel='canonical' href='https://jeffry.in' itemProp='url' />
        <meta name='twitter:url' property='og:url' content='https://jeffry.in' />
        <meta name='twitter:title' property='og:title' content='Jeffry.in' />
      </Helmet>
      <hr />
      {generatePosts(posts)}
    </main>
  </Layout>
)

export const pageQuery = graphql`
  query IndexQuery {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      edges {
        node {
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            featured_image
            path
            meta
            title
          }
        }
      }
    }
  }
`
